import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for f in p['frameworks']:
            for pkg in f['topLevelPackages']:
                result[(proj, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        unchanged.append((k[0], k[1], bv))
    else:
        changes.append((k[0], k[1], bv, av))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]}')
else:
    print('No version changes detected - conversion is fully version-neutral.')

print(f'\nUnchanged: {len(unchanged)} packages')
for u in unchanged:
    print(f'  {u[0]} | {u[1]} | {u[2]}')
"

